18	export async function POST(req: NextRequest) {
19	  const body = await req.json();
20	  const habit = {
21	    id: crypto.randomUUID(),
22	    userId: "demo",
23	    ...body,
24	    isActive: true,
25	    createdAt: new Date().toISOString(),
26	    updatedAt: new Date().toISOString(),
