1	import { NextRequest, NextResponse } from "next/server";
2	import { store } from "@/lib/store";
3	import { getAIRecommendation } from "@/lib/claude";
4	
5	export async function POST(req: NextRequest) {
6	  const { type, data, prompt } = await req.json();
7	
8	  try {
9	    if (type === "weekly") {
10	      // Gather last 7 days of data
11	      const habits = store.habits.filter((h: any) => h.isActive);
12	      const today = new Date();
13	      const logs: any[] = [];
14	      for (let i = 6; i >= 0; i--) {
15	        const d = new Date(today);
16	        d.setDate(d.getDate() - i);
17	        const dateStr = d.toISOString().split("T")[0];
18	        const dayLogs = store.habitLogs.filter(
19	          (l: any) => l.date === dateStr
20	        );
21	        logs.push({ date: dateStr, completed: dayLogs.filter((l: any) => l.completed).length, total: dayLogs.length });
22	      }
23	
24	      const message = `作为个人成长教练，根据以下本周数据给一段简短的洞察（200字以内）：
25	完成情况: ${logs.map((l) => `${l.date}: ${l.completed}/${l.total}`).join(", ")}
26	活跃习惯: ${habits.map((h: any) => h.title).join("、")}
27	指出1-2个趋势，给出1条具体改进建议。语气像帝王侍读。`;
28	
29	      const text = await getAIRecommendation(message);
30	      return NextResponse.json({ text });
31	    }
32	
33	    if (type === "review") {
34	      const message = `用户刚做了今日复盘：评分${data.score}/5，总结："${data.summary}"，亮点："${data.highlight}"，不足："${data.lowlight}"。请用帝王侍读的语气给一段鼓励+建议（100字以内）。`;
35	      const text = await getAIRecommendation(message);
36	      return NextResponse.json({ text });
37	    }
38	
39	    if (type === "generate-habits") {
40	      const message = `用户描述了以下目标："${prompt}"。请帮用户拆解成3-5个具体的每日习惯，每个习惯格式为：- [领域] 习惯名称：具体描述（目标值+单位）。直接给列表，不要多余的话。`;
41	      const text = await getAIRecommendation(message);
42	      return NextResponse.json({ text });
43	    }
44	
45	    if (type === "daily-summary") {
46	      const habits = store.habits.filter((h: any) => h.isActive);
47	      const todayStr = new Date().toISOString().split("T")[0];
48	      const todayLogs = store.habitLogs.filter((l: any) => l.date === todayStr);
49	      const completedCount = todayLogs.filter((l: any) => l.completed).length;
50	      const totalCount = habits.length;
51	      const completionRate = totalCount > 0 ? Math.round((completedCount / totalCount) * 100) : 0;
52	
53	      // 连续天数
54	      let streak = 0;
55	      const now = new Date();
56	      for (let i = 0; i < 365; i++) {
57	        const d = new Date(now);
58	        d.setDate(d.getDate() - i);
59	        const ds = d.toISOString().split("T")[0];
60	        const dayCompleted = store.habitLogs.filter((l: any) => l.date === ds && l.completed).length;
61	        if (dayCompleted > 0) streak++;
62	        else break;
63	      }
64	
65	      // 昨日复盘
66	      const yesterday = new Date(now);
67	      yesterday.setDate(yesterday.getDate() - 1);
68	      const yesterdayStr = yesterday.toISOString().split("T")[0];
69	      const yesterdayReview = (store.dailyReviews || []).find((r: any) => r.date === yesterdayStr);
70	
71	      const message = `用户今日打卡情况：完成 ${completedCount}/${totalCount} 项习惯，完成率 ${completionRate}%，连续 ${streak} 天。${yesterdayReview ? `昨日复盘："${yesterdayReview.summary}"` : ""}请用帝王侍读的口吻，给一段温暖、简洁的今日小结（80-120字），既肯定成就又温和提醒不足。`;
72	
73	      const text = await getAIRecommendation(message);
74	      return NextResponse.json({ text });
75	    }
76	
77	    if (type === "daily-goals") {
78	      const habits = store.habits.filter((h: any) => h.isActive);
79	      const now = new Date();
80	
81	      // 近14天各习惯完成率
82	      const habitStats = habits.map((h: any) => {
83	        let completed = 0;
84	        let total = 0;
85	        for (let i = 1; i <= 14; i++) {
86	          const d = new Date(now);
87	          d.setDate(d.getDate() - i);
88	          const ds = d.toISOString().split("T")[0];
89	          const log = store.habitLogs.find((l: any) => l.habitId === h.id && l.date === ds);
90	          total++;
91	          if (log?.completed) completed++;
92	        }
93	        return { title: h.title, completionRate: Math.round((completed / total) * 100), streak: 0 };
94	      });
95	
96	      // 查断档
97	      habitStats.forEach((hs: any) => {
98	        let s = 0;
99	        for (let i = 1; i <= 14; i++) {
100	          const d = new Date(now);
101	          d.setDate(d.getDate() - i);
102	          const ds = d.toISOString().split("T")[0];
103	          const log = store.habitLogs.find((l: any) => l.habitId === habits.find((h: any) => h.title === hs.title)?.id && l.date === ds);
104	          if (!log?.completed) break;
105	          s++;
106	        }
107	        hs.streak = s;
108	      });
109	
110	      const message = `用户近14天各习惯完成率：${habitStats.map((hs: any) => `${hs.title}(${hs.completionRate}%)`).join("，")}。连续未做的习惯：${habitStats.filter((hs: any) => hs.streak === 0).map((hs: any) => hs.title).join("、") || "无"}。请基于以上数据，推荐2-3条明日具体可执行的行动建议。返回 JSON 数组格式：[{"title":"...","detail":"...","reason":"..."}]，不要 markdown 包裹，只返回纯 JSON。`;
111	
112	      const text = await getAIRecommendation(message);
113	      try {
114	        const goals = JSON.parse(text);
115	        return NextResponse.json({ goals: Array.isArray(goals) ? goals : [] });
116	      } catch {
117	        return NextResponse.json({ goals: [] });
118	      }
119	    }
120	
121	    return NextResponse.json({ error: "Unknown type" }, { status: 400 });
122	  } catch (err) {
123	    // If Claude API is not configured, return a fallback message
124	    return NextResponse.json({
125	      text: type === "weekly"
126	        ? "本周数据已汇总。完成率最高的领域是健身上午时段，建议将重要习惯安排在精力充沛的早晨。连续3天以上达标的习惯会形成惯性，再坚持一下。"
127	        : type === "review"
128	        ? "每日三省，便是精进。今日无论得失，皆是明日之基石。坚持复盘，自见成效。"
129	        : "根据你的目标，建议从每天25分钟的微习惯开始，不求多但求持续。三周后自然成习惯。",
130	    });
131	  }
132	}
