Let me think about the progress and days remaining calculations:

```typescript
function calculateProgress(goal: Goal): number {
  const { startValue, targetValue, currentValue } = goal;
  if (targetValue > startValue) {
    // Positive direction (e.g., increase running distance)
    const progress = (currentValue - startValue) / (targetValue - startValue);
    return Math.min(Math.max(progress, 0), 1);
  } else {
    // Negative direction (e.g., lose weight)
    const progress = (startValue - currentValue) / (startValue - targetValue);
    return Math.min(Math.max(progress, 0), 1);
  }
}

function calculateDaysRemaining(deadline: string | null): number | null {
  if (!deadline) return null;
  const now = new Date();
  const deadlineDate = new Date(deadline);
  const diff = deadlineDate.getTime() - now.getTime();
  return Math.ceil(diff / (1000 * 60 * 60 * 24));
}
```

