import { NextRequest, NextResponse } from "next/server";
import { store } from "@/lib/store";

export async function POST(req: NextRequest) {
  const { habitId, date, value, note, mood } = await req.json();

  const existingIdx = store.habitLogs.findIndex(
    (l: any) => l.habitId === habitId && l.date === date
  );

  if (existingIdx !== -1) {
    // Toggle: if completed, uncheck; if not, check
    store.habitLogs[existingIdx].completed = !store.habitLogs[existingIdx].completed;
    return NextResponse.json(store.habitLogs[existingIdx]);
  }

  const log = {
    id: crypto.randomUUID(),
    habitId,
    userId: "demo",
    date,
    value: value || 1,
    completed: true,
    note: note || null,
    mood: mood || null,
    createdAt: new Date().toISOString(),
  };
  store.habitLogs.push(log);
  return NextResponse.json(log);
}

import { NextRequest, NextResponse } from "next/server";
import { store } from "@/lib/store";

export async function GET(req: NextRequest) {
  const date = req.nextUrl.searchParams.get("date");
  const review = store.dailyReviews.find(
    (r: any) => r.userId === "demo" && r.date === date
  );
  return NextResponse.json(review || null);
}

export async function POST(req: NextRequest) {
  const body = await req.json();
  const existing = store.dailyReviews.findIndex(
    (r: any) => r.userId === "demo" && r.date === body.date
  );

  const review = {
    id: crypto.randomUUID(),
    userId: "demo",
    ...body,
    aiFeedback: body.aiFeedback || null,
    aiSummary: body.aiSummary || null,
    userSupplement: body.userSupplement || null,
    createdAt: new Date().toISOString(),
  };

  if (existing !== -1) {
    store.dailyReviews[existing] = { ...store.dailyReviews[existing], ...review };
  } else {
    store.dailyReviews.push(review);
  }

  return NextResponse.json(review);
}

