// ── Goal helpers ──

export function createGoal(data: {
  title: string;
  description?: string;
  startValue: number;
  targetValue: number;
  currentValue?: number;
  unit: string;
  deadline?: string;
  linkedHabitIds?: string[];
}): Goal {
  const goal: Goal = {
    id: crypto.randomUUID(),
    userId: "demo",
    title: data.title,
    description: data.description || null,
    startValue: data.startValue,
    targetValue: data.targetValue,
    currentValue: data.currentValue ?? data.startValue,
    unit: data.unit,
    deadline: data.deadline || null,
    linkedHabitIds: data.linkedHabitIds || [],
    isArchived: false,
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString(),
  };
  store.goals.push(goal);
  return goal;
}

export function getGoalById(id: string): Goal | undefined {
  return store.goals.find((g: Goal) => g.id === id);
}

export function deleteGoal(id: string): void {
  store.goals = store.goals.filter((g: Goal) => g.id !== id);
  store.goalLogs = store.goalLogs.filter((l: GoalLog) => l.goalId !== id);
}

// ── GoalLog helpers ──

export function createGoalLog(data: {
  goalId: string;
  previousValue: number;
  newValue: number;
  delta: number;
  note?: string | null;
}): GoalLog {
  const log: GoalLog = {
    id: crypto.randomUUID(),
    goalId: data.goalId,
    userId: "demo",
    previousValue: data.previousValue,
    newValue: data.newValue,
    delta: data.delta,
    note: data.note ?? null,
    createdAt: new Date().toISOString(),
  };
  store.goalLogs.push(log);
  return log;
}

export function getGoalLogsByGoalId(goalId: string): GoalLog[] {
  return store.goalLogs.filter((l: GoalLog) => l.goalId === goalId);
}

// ── Computation helpers ──

export function calculateProgress(goal: Goal): number {
  const { startValue, targetValue, currentValue } = goal;
  if (targetValue === startValue) return 0;
  if (targetValue > startValue) {
    // Positive direction: e.g. increase running distance
    return Math.min(Math.max((currentValue - startValue) / (targetValue - startValue), 0), 1);
  }
  // Negative direction: e.g. lose weight
  return Math.min(Math.max((startValue - currentValue) / (startValue - targetValue), 0), 1);
}

export function calculateDaysRemaining(deadline: string | null): number | null {
  if (!deadline) return null;
  const now = new Date();
  const deadlineDate = new Date(deadline);
  const diff = deadlineDate.getTime() - now.getTime();
  return Math.ceil(diff / (1000 * 60 * 60 * 24));
}

