import { NextRequest, NextResponse } from "next/server";
import { store, createGoal, getGoalById, deleteGoal, createGoalLog, calculateProgress, calculateDaysRemaining } from "@/lib/store";

const todayStr = () => new Date().toISOString().split("T")[0];

function enrichGoal(g: any) {
  const goal = { ...g };
  const progress = calculateProgress(goal);
  const daysRemaining = calculateDaysRemaining(goal.deadline);

  const linkedHabits = (goal.linkedHabitIds || []).map((id: string) => {
    const habit = store.habits.find((h: any) => h.id === id);
    if (!habit) return null;
    const log = store.habitLogs.find((l: any) => l.habitId === id && l.date === todayStr());
    return { id: habit.id, title: habit.title, completed: log?.completed || false };
  }).filter(Boolean);

  return {
    ...goal,
    linkedHabits,
    progress,
    daysRemaining,
    linkedHabitsCompleted: linkedHabits.filter((h: any) => h.completed).length,
    linkedHabitsTotal: linkedHabits.length,
  };
}

export async function GET(req: NextRequest) {
  const includeArchived = req.nextUrl.searchParams.get("includeArchived") === "true";

  const goals = store.goals
    .filter((g: any) => includeArchived || !g.isArchived)
    .map(enrichGoal);

  return NextResponse.json(goals);
}

export async function POST(req: NextRequest) {
  const body = await req.json();

  if (!body.title || typeof body.title !== "string" || body.title.length < 1 || body.title.length > 50) {
    return NextResponse.json({ error: "Title is required (1-50 characters)" }, { status: 400 });
  }
  if (body.startValue === undefined || body.targetValue === undefined) {
    return NextResponse.json({ error: "startValue and targetValue are required" }, { status: 400 });
  }
  if (body.targetValue === body.startValue) {
    return NextResponse.json({ error: "targetValue must differ from startValue" }, { status: 400 });
  }
  if (!body.unit || typeof body.unit !== "string") {
    return NextResponse.json({ error: "unit is required" }, { status: 400 });
  }

  const goal = createGoal(body);
  return NextResponse.json(goal, { status: 201 });
}

export async function PUT(req: NextRequest) {
  const { id, note, ...updates } = await req.json();

  const existing = getGoalById(id);
  if (!existing) {
    return NextResponse.json({ error: "Not found" }, { status: 404 });
  }

  if (Object.keys(updates).length === 0) {
    return NextResponse.json({ error: "No changes detected" }, { status: 400 });
  }

  // Auto-create GoalLog when currentValue changes
  if (updates.currentValue !== undefined && updates.currentValue !== existing.currentValue) {
    const previousValue = existing.currentValue;
    const delta = updates.currentValue - previousValue;
    createGoalLog({
      goalId: id,
      previousValue,
      newValue: updates.currentValue,
      delta,
      note: note || null,
    });
  }

  const idx = store.goals.findIndex((g: any) => g.id === id);
  store.goals[idx] = { ...store.goals[idx], ...updates, updatedAt: new Date().toISOString() };
  return NextResponse.json(store.goals[idx]);
}

export async function DELETE(req: NextRequest) {
  const { id } = await req.json();

  const existing = getGoalById(id);
  if (!existing) {
    return NextResponse.json({ error: "Not found" }, { status: 404 });
  }

  deleteGoal(id);
  return NextResponse.json({ ok: true });
}

import { NextRequest, NextResponse } from "next/server";
import { store } from "@/lib/store";

export async function GET(
  req: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  const { id } = await params;

  const goal = store.goals.find((g: any) => g.id === id);
  if (!goal) {
    return NextResponse.json({ error: "Not found" }, { status: 404 });
  }

  const logs = store.goalLogs
    .filter((l: any) => l.goalId === id)
    .sort((a: any, b: any) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());

  return NextResponse.json(logs);
}

import { NextRequest, NextResponse } from "next/server";
import { store, calculateProgress, calculateDaysRemaining } from "@/lib/store";
import { getAIRecommendation } from "@/lib/claude";

export async function GET(req: NextRequest) {
  const type = req.nextUrl.searchParams.get("type");

  try {
    if (type === "progress") {
      return await handleProgressAnalysis(req);
    }
    if (type === "recommend") {
      return await handleRecommendation();
    }
    return NextResponse.json({ error: "Unknown type" }, { status: 400 });
  } catch (err) {
    return NextResponse.json({
      trend: "unknown",
      assessment: "数据不足，继续记录即可看到趋势",
      canMeetDeadline: null,
      suggestions: ["保持当前节奏", "定期更新数值"],
      adjustDeadline: false,
    });
  }
}

async function handleProgressAnalysis(req: NextRequest) {
  const goalId = req.nextUrl.searchParams.get("goalId");
  if (!goalId) {
    return NextResponse.json({ error: "goalId is required" }, { status: 400 });
  }

  const goal = store.goals.find((g: any) => g.id === goalId);
  if (!goal) {
    return NextResponse.json({ error: "Goal not found" }, { status: 404 });
  }

  const daysRemaining = calculateDaysRemaining(goal.deadline);
  const progress = calculateProgress(goal);

  // Logs sorted ascending
  const logs = store.goalLogs
    .filter((l: any) => l.goalId === goalId)
    .sort((a: any, b: any) => new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime());

  const recentLogsStr = logs.slice(-7).map((l: any) => {
    const sign = l.delta > 0 ? "+" : "";
    const notePart = l.note ? ` - ${l.note}` : "";
    return `${l.createdAt}: ${l.previousValue} → ${l.newValue} (${sign}${l.delta})${notePart}`;
  }).join("\n");

  // Linked habits 14-day completion
  const now = new Date();
  const linkedHabitsInfo = (goal.linkedHabitIds || []).map((id: string) => {
    const habit = store.habits.find((h: any) => h.id === id);
    if (!habit) return null;
    let completed = 0;
    let total = 0;
    for (let i = 1; i <= 14; i++) {
      const d = new Date(now);
      d.setDate(d.getDate() - i);
      const ds = d.toISOString().split("T")[0];
      const log = store.habitLogs.find((l: any) => l.habitId === id && l.date === ds);
      total++;
      if (log?.completed) completed++;
    }
    return `${habit.title}: ${total > 0 ? Math.round((completed / total) * 100) : 0}%`;
  }).filter(Boolean).join("\n");

  const direction = goal.targetValue > goal.startValue ? "增加型" : "减少型";

  const prompt = `作为帝王侍读，分析以下目标进展：

目标：${goal.title}
${direction}目标
起始值：${goal.startValue}${goal.unit} → 目标值：${goal.targetValue}${goal.unit}
当前值：${goal.currentValue}${goal.unit}（进度 ${Math.round(progress * 100)}%）
${goal.deadline ? `截止日期：${goal.deadline}\n剩余天数：${daysRemaining}` : "截止日期：无"}
${goal.description ? `描述：${goal.description}` : ""}

历史记录（最近 7 条）：
${recentLogsStr || "暂无记录"}

关联习惯近 14 天完成率：
${linkedHabitsInfo || "无关联习惯"}

请给出：
1. 趋势判断（按当前速度能否按时达标）
2. 1-2 条具体调整建议
3. 是否需要调整目标值或截止日期

返回 JSON：{"trend": "accelerating|on-track|slowing|stuck|unknown", "assessment": "一句话判断", "canMeetDeadline": true|false, "suggestions": ["建议1", "建议2"], "adjustDeadline": true|false}`;

  const text = await getAIRecommendation(prompt);
  try {
    const result = JSON.parse(text);
    return NextResponse.json({
      trend: result.trend || "unknown",
      assessment: result.assessment || "数据不足，继续记录即可看到趋势",
      canMeetDeadline: result.canMeetDeadline ?? null,
      suggestions: Array.isArray(result.suggestions) ? result.suggestions : ["保持当前节奏", "定期更新数值"],
      adjustDeadline: !!result.adjustDeadline,
    });
  } catch {
    return NextResponse.json({
      trend: "unknown",
      assessment: "数据不足，继续记录即可看到趋势",
      canMeetDeadline: null,
      suggestions: ["保持当前节奏", "定期更新数值"],
      adjustDeadline: false,
    });
  }
}

async function handleRecommendation() {
  const now = new Date();

  // Active habits with 14-day completion
  const activeHabits = store.habits.filter((h: any) => h.isActive);
  const habitStats = activeHabits.map((h: any) => {
    let completed = 0;
    let total = 0;
    for (let i = 1; i <= 14; i++) {
      const d = new Date(now);
      d.setDate(d.getDate() - i);
      const ds = d.toISOString().split("T")[0];
      const log = store.habitLogs.find((l: any) => l.habitId === h.id && l.date === ds);
      total++;
      if (log?.completed) completed++;
    }
    return {
      title: h.title,
      domainId: h.domainId || "",
      completionRate: total > 0 ? Math.round((completed / total) * 100) : 0,
    };
  });

  const existingGoals = store.goals.map((g: any) => g.title);

  const habitsStr = habitStats.map((h: any) => `${h.title} (${h.domainId}): ${h.completionRate}%`).join("\n");
  const existingStr = existingGoals.join("、") || "无";

  const prompt = `用户当前有以下习惯（近 14 天完成率）：
${habitsStr}

已有目标：${existingStr}

请推荐 2-3 个适合用户的新目标，每个目标应符合用户的习惯组合，目标值要具体可量化。
格式：严格返回 JSON 数组，不要任何 markdown 包裹：
[{"title":"目标名称","description":"简短理由","suggestedStartValue":0,"suggestedTargetValue":0,"unit":"单位","suggestedDeadlineDays":30}]`;

  try {
    const text = await getAIRecommendation(prompt);
    const recommendations = JSON.parse(text);
    return NextResponse.json(Array.isArray(recommendations) ? recommendations : []);
  } catch {
    return NextResponse.json([]);
  }
}
